// Package iata validates IATA location codes against the real-world code
// assignments. The embedded set is generated from the public-domain OurAirports
// dataset (https://ourairports.com/data/, airports.csv: open airports with an
// iata_code) plus the IATA metropolitan-area codes (LON, NYC, TYO, …) that
// designate multi-airport cities rather than airports.
//
// Regenerate by re-running the extraction described in the repo history against
// a fresh airports.csv; codes are 3 ASCII uppercase letters, sorted, concatenated.
package iata

import "sort"

// Valid reports whether code is an assigned IATA location code. The input must
// already be normalized to 3 uppercase ASCII letters.
func Valid(code string) bool {
	if len(code) != 3 {
		return false
	}
	n := len(codes) / 3
	i := sort.Search(n, func(i int) bool { return codes[i*3:i*3+3] >= code })
	return i < n && codes[i*3:i*3+3] == code
}

